#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}vector<int> g[100005];
int t,n,a[100005],r,ans;
void dfs(int fa,int x)
{
	if(!ans) return;
	int s=0;
	for(int i=0;i<g[x].size();i++)
	{
		if(g[x][i]==fa) continue;
		dfs(x,g[x][i]);
		s+=a[g[x][i]];
	}
	if(s) a[x]=1;
	if((x==r&&s>2)||(x!=r)&&s>1) ans=0;
}
int main()
{
	int u,v;
	scanf("%d",&t);
	while(t--)
	{
		scanf("%d",&n);
		r=0,ans=1;
		for(int i=1;i<=n;i++)
		{
			g[i].clear();
			scanf("%d",&a[i]);
			if(a[i]&&!r) r=i; 
		}
		for(int i=1;i<n;i++)
		{
			scanf("%d%d",&u,&v);
			g[u].push_back(v);
			g[v].push_back(u);
		}
		dfs(0,r);
		if(ans) printf("Yes\n");
		else printf("No\n");
	}
	return 0;
}
